var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"괜찮아요, 크레데레? 몸에 무슨 문제 생긴 거 아니에요?","JPN":"クレデレ、大丈夫なんですか？　身体に異常は？","ENG":"Are you okay, Credere? Did anything happen to your body?","TWN":"沒、沒事吧，克蕾妲莉？身體沒有出什麼問題吧？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"문제없습니다. 아까도 말했지만 크레데레는 장수할 거라서요.","JPN":"問題ありません。さっきも言いましたが、クレデレは長生きする予定なので。","ENG":"All good. As Credere said earlier, Credere is going to live long and prosper.","TWN":"沒事的。剛才也說過，克蕾妲莉會長壽的。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아무리 그래도 그렇지. 그렇게 상자를 막 열면 어떡해요?","JPN":"だからって、いきなり箱を開けたらびっくりするじゃないですか。","ENG":"Still, you can't just open the chest on your own like that.","TWN":"再怎麼說也不能那樣。怎麼能擅自打開箱子呢？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"저희가 한 말 못 들었어요?","JPN":"私たちの話を聞いてなかったんですか？","ENG":"Didn't you hear what we said?","TWN":"沒聽到說箱子上有詛咒嗎……？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"하지만 유피. 크레데레는 실제로 멀쩡하지 않나요.","JPN":"でもユピ、クレデレはなんともないですよ。","ENG":"But, Yuppie. Look. Credere is fine.","TWN":"但是悠菲，克蕾妲莉不是好好的嗎。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"어…? 그러고 보니 그렇네요?","JPN":"あれ？　そういえばそうですね。","ENG":"Oh... You're right.","TWN":"嗯……這麼說來，好像是欸……？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"상자 안에 대체 뭐가 들었길래…….","JPN":"じゃあ箱の中身っていったい……","ENG":"So, what was in the chest...?","TWN":"箱子裡到底裝了什麼……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"결국… 열어버렸어.","JPN":"結局……開けられてしまった。","ENG":"It's... open.","TWN":"最後……還是打開了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"내 존엄성이… 지금까지 쌓아온 이미지가…….","JPN":"私の尊厳……今まで築き上げてきたブランディングが……","ENG":"No... My dignity... My reputation...","TWN":"我的尊嚴……我一直以來建立的形象……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"꽤 오래된 물건인가 봐. 종이의 내용이 이곳저곳 훼손돼 있어.","JPN":"結構古いみたい。一部は読めそうにないね。","ENG":"It must be quite old. Several parts of the paper are damaged.","TWN":"看起來是相當有年代的東西。紙上的內容都已經損壞了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그림 같은 것도 그려져 있는데, 설마 암호문인 걸까요?","JPN":"絵みたいのも描いてありますけど、暗号でしょうか？","ENG":"It looks like there's a drawing here, too. Do you think it's some kind of code?","TWN":"上面還畫著一些圖畫，難道是密碼嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"크레데레는 눈을 왜 그렇게 한쪽으로 몰아서 떠요?","JPN":"クレデレ、片目を瞑ってどうしたんですか？","ENG":"Why are you crossing your eyes like that, Credere?","TWN":"克蕾妲莉為什麼要斜著眼睛？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"천재인 크레데레는 이게 매직아이일 가능성을 떠올렸습니다.","JPN":"天才クレデレはこれがマジックアイである可能性を思いつきました。","ENG":"The genius Credere has realized that this might be an autostereogram.","TWN":"天才的克蕾妲莉認為這可能是立體圖。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이건 글자랑 그림이 섞여 있잖아요. 그런다고 뭐가 보이겠어요?","JPN":"絵と文字が混ざっていますが、片目で見て何かわかるのでしょうか？","ENG":"This has both letters and drawings. Crossing your eyes won't help.","TWN":"字和圖都混在一起了，這樣能看出什麼來嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"흡.","JPN":"ふうっ。","ENG":"Hmpf.","TWN":"哈。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"잠시만요. 내용이 훼손돼 있다고요?","JPN":"ちょっと。一部は読めそうにない？","ENG":"Wait. The paper is damaged?","TWN":"等一下，內容毀損了嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"후후후…….","JPN":"ふふふ……","ENG":"Fu fu fu...","TWN":"呵呵……呵呵呵……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"유감이군요. 아무래도 상자의 저주가 내용물을 훼손시킨 모양입니다.","JPN":"残念でしたね。どうやら箱の呪いのせいで中身が毀損されてしまったようです。","ENG":"What a shame. It seems like the curse damaged the contents.","TWN":"真遺憾。看來是箱子的詛咒破壞了裡面的物品。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아까는 상자를 연 사람이 어쩌구 하시지 않았어요?","JPN":"さっきは箱を開けた者がどうとか言っていませんでした？","ENG":"Didn't you say that the curse would affect the person who opened it?","TWN":"你剛剛不是說開箱子的人會怎樣嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"제가 잠시 착각했나 보군요. 다친 사람도 없으니 좋은 게 좋은 거 아니겠습니까?","JPN":"私の勘違いだったようです。　誰にも被害は起きていませんし、万事オッケーではないでしょうか？","ENG":"I must have made a mistake. Anyway. No one is hurt, so let us rejoice in this victory.","TWN":"看來我剛才有些誤會。總之沒人受傷就算是不幸中的大幸吧？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"오해도 풀렸으니 돌아가죠. 두 분 문제는 제가 해결해드리겠습니다.","JPN":"誤解も解けたことですし、さあ戻りましょう。お二人方に起きたことは、私が収拾をつけるので。","ENG":"We can return now, as the misunderstanding has been resolved. I will take care of your issues.","TWN":"誤會解除了，我們回去吧。兩位的問題我會幫你們解決的。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"……으음.","JPN":"……ううん。","ENG":"...Hmm.","TWN":"……嗯嗯。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"가까이서 본다고 뭐가 보이겠습니까? 미래전략실장도 그쯤하고.","JPN":"近くから見たって何か見えるわけではありませんよ。未来戦略室長ももうその辺にしてはどうです？","ENG":"Staring at it up close won't help. You too, chief of the Future Strategy Department.","TWN":"湊這麼近能看出什麼呢？未來戰略室長也別看了吧？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Wait.","TWN":"呃，等一下。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"나만의 멋진 기술 이름 짓는 법.","JPN":"私流、かっこいい技名の付け方。","ENG":"How to make your own cool skill name.","TWN":"給自己取酷炫技能名字的方法——"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"일. 내 이름이나 존경하는 사람의 이름이 들어가야 한다.","JPN":"そのイチ。自分が尊敬する相手の名前を入れる。","ENG":"One. It has to contain your own name or the name of someone you look up to.","TWN":"一、必須包含我的名字或我尊敬的人的名字。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이. 뒤에 붙는 단어는 최대한 멋있는 걸로. 입에 척척 감기는 영어 단어가 제일 좋음.","JPN":"そのニ。名前の後ろはかっこいい単語を使う。叫ぶと気持ちのいい英単語を使用するといい。","ENG":"Two. The word that comes after has to be something really awesome. Like a word that sounds fancy for no reason.","TWN":"二、語尾的詞要儘量酷炫。最好是選擇朗朗上口的單字。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"삼. 검을 휘두르는 동안 외쳐야 하니 너무 짧으면 안 돼. 길이는 적절한 게 가장 좋아.","JPN":"そのサン。剣を振り終わるまで叫び続けられる長さにする。","ENG":"Three. It has to be long enough so that you can shout it while swinging your sword. Make it decently long.","TWN":"三、揮劍的時候要喊出來，所以不能太短或太長。長度適中是最好的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L45_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"어때, 멀대? 너도 이 세 가지만 지키면 멋진 필살기를 만들 수 있다고?","JPN":"どう、ヒョロガリ？ あなたもこの3つさえ覚えておけば、かっこいい必殺技が編み出せるようになるわよ。","ENG":"What do you think, Beanstalk? Follow these three steps, and you, too, can give your special move a cool name.","TWN":"怎麼樣，傻大個？你只要遵守這三點，也能創造出帥氣的必殺技喔？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"음, 그게 수연아?","JPN":"あのー、キズナ？","ENG":"Um, Sooyeon?","TWN":"嗯，秀妍？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"혹시……","JPN":"もしかして……","ENG":"Are you...","TWN":"你是認真……？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"진심으로 하는 소린가?","JPN":"それ、本気で言ってるんですか？","ENG":"Seriously?","TWN":"這個……不是玩笑吧？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"농담 정도는 구분하시죠, 유피. 크레데레도 저러진 않아요.","JPN":"冗談に決まっているでしょう、ユピ。こんなこと、クレデレでも書きませんよ。","ENG":"You should know how to distinguish jokes, Yuppie. Not even Credere would do this.","TWN":"請區分下開玩笑的程度吧，悠菲。就算克蕾妲莉也不會那樣。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그쵸? 웬 초등학생도 안 쓸 법한 내용에 잠깐 넋이 나갔나 봐요.","JPN":"ですよね？　小学生でも書かないようなものを見たせいで、ちょっと感覚が狂っちゃって。","ENG":"Right? I lost it for a second. Not even elementary school students would write this.","TWN":"對、對吧？我剛才可能被一些連小學生都不會寫的內容給嚇到了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"이…","JPN":"カ……？","ENG":"Lee...","TWN":"李……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"부사장 아줌마? 왜 그래, 어디 아파?","JPN":"副社長のおばさん？　どうしたの？","ENG":"Vice President? What is it? Are you sick?","TWN":"副總大嬸？怎麼了，是不是哪裡不舒服？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"이……!","JPN":"カ……！","ENG":"Lee...!","TWN":"李……！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"서, 설마 상자의 저주에 걸린 거 아니에요?","JPN":"ま、まさか箱の呪いが？","ENG":"W-wait, do you think the chest put the curse on her?","TWN":"難道是中了寶箱的詛咒嗎？！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"헉. 종이에 적힌 내용도 저주에 걸린 인간이 실성한 뒤에 적은 내용일지도 모릅니다.","JPN":"はっ！　もしかしたらこの内容も、呪いにかかった人間が正気を失って書いたものかもしれません。","ENG":"*Gasp* Perhaps this was written by someone who lost their mind after getting cursed.","TWN":"嚇！也許紙上內容就是中了詛咒的人發瘋後寫下的。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"아픈 거라면 크레데레가 호- 불어드릴까요?","JPN":"どこか具合が悪いのなら、クレデレが痛いのとんでいけ～ってやってあげましょうか？","ENG":"Would you like Credere to sing to make it all better?","TWN":"如果覺得哪裡難受的話，要讓克蕾妲莉給你呼呼嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"이수여어어어언──! 스트라이크으으으으──!","JPN":"カナミ・キズナァァァァ──！　ストラァァァァ──イクッ！","ENG":"Lee Sooyeoooooonnnnn! STRIIIIIKE!!!","TWN":"李秀妍————！！爆斬————！！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"푸하-!","JPN":"ぷはーっ！","ENG":"Haaah!","TWN":"噗哈——!"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"헉… 허억…….","JPN":"はぁ……はぁ……","ENG":"*Huff* *Huff*","TWN":"咳……咳咳……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"무슨 일이 일어난 거지… 갑자기 눈앞이 번쩍하고 빛난 것까진 기억하는데…….","JPN":"何が起きたんだろう……目の前が急にピカッと光って……それで……","ENG":"What happened...? I remember something flashing brightly before my eyes.","TWN":"發生了什麼事……我只記得眼前突然閃過一道光……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"으으. 다들 다친 덴 없으세요?","JPN":"うう。みなさん、大丈夫ですか？","ENG":"Argh. Is everyone okay?","TWN":"呃呃。大家都沒受傷吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레는 높이 뛰기 자체 신기록을 갱신했습니다.","JPN":"クレデレは高跳びの自己記録を更新しました。","ENG":"Credere just broke her own record for jumping height.","TWN":"克蕾妲莉刷新了跳高的個人紀錄。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"다른 말로는 죽을 뻔했어요.","JPN":"つまり、本気で死にかけたってことです。","ENG":"In other words, Credere almost died.","TWN":"換句話說，差點就死了。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"평소대로인 걸 보니 멀쩡한가 보네요.","JPN":"いつものクレデレですね。無事でよかったです。","ENG":"You sound normal enough.","TWN":"唔，像往常一樣，看來是沒事。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"시그마는 어때요?","JPN":"シグマは？","ENG":"What about you, Sigma?","TWN":"西格瑪呢？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"시그마?","JPN":"シグマ？","ENG":"Sigma?","TWN":"西格瑪？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"에잇-!","JPN":"えいっ！","ENG":"Hmpf!","TWN":"嘿——!"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"쿨럭! 쿨럭!","JPN":"ゲホッ！　ゲホッ！","ENG":"*Cough* *Cough*","TWN":"咳咳！咳咳！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"으으. 뭐하는 거예요, 갑자기!","JPN":"うっ、いきなり何をするんですか？","ENG":"Argh! What are you doing?!","TWN":"呃呃。你幹什麼啦，突然這樣！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"후후. 그럼 안돼, 유피. 원래 해적은 바다에서 방심하지 않는 법이라구.","JPN":"ふふ、ダメだよ、ユピ。海賊が海に出たのに油断しちゃ。","ENG":"Ha hah. A pirate should never let their guard down at sea, Yuppie.","TWN":"哼哼。那可不行，悠菲。真正的海盜在海上可不能掉以輕心。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DUCK_DEBT_NULL_NULL","text":{"KOREA":"물론. 바다를 거느려야 진정한 해적이라고 할 수 있지.","JPN":"もちろん。海を駆け回ってこそ、真の海賊といえるけどな。","ENG":"That is correct. You cannot call yourself a true pirate unless you dominate the seas!","TWN":"當然。只有掌控大海，才能稱得上是真正的海盜。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DUCK_DEBT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"앗. 너는…….","JPN":"あっ、あなたは……","ENG":"Oh, you're...","TWN":"啊。你是……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DUCK_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DUCK_DEBT_NULL_NULL","text":{"KOREA":"그래. 이 몸이야말로 바다를 아우르는 세기의 대해적-","JPN":"ああ、この俺様は海を根城にする世紀の大海賊ー","ENG":"Indeed. I am the great pirate of the century who oversees the ocean.","TWN":"沒錯。正是我，掌管大海的世紀大海盜——"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DUCK_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"캡틴 바르벡사클론?","JPN":"キャプテン・バルベックサクローン？","ENG":"Captain Barbexaclone?","TWN":"巴拉巴巴巴隊長？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"바르바로사예요 크레데레.","JPN":"バルバロッサです、クレデレ。","ENG":"It's Barbarossa.","TWN":"是巴巴羅薩隊長，克蕾妲莉。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그런데 바르바로사 씨가 왜 여기 있는 거예요?","JPN":"ところで、どうしてバルバロッサさんがここにいるんですか？","ENG":"Anyway, what are you doing here, Barbarossa?","TWN":"不過，巴巴羅薩隊長為什麼會在這裡？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DUCK_DEBT_NULL_NULL","text":{"KOREA":"흥. 설마 대해적인 내가 아무 이유 없이 네놈들에게 힘을 빌려줄 거라 생각한 거냐?","JPN":"ふん、まさか大海賊である俺が、何の理由もなしに貴様たちに力を貸すと思ったか？","ENG":"Hmph. Did you really think a great pirate like me would lend a hand with no ulterior motives?","TWN":"哼。難道你以為我這位大海之王會無緣無故地借給你們力量嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DUCK_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DUCK_DEBT_NULL_NULL","text":{"KOREA":"보물을 넘겨라, 풋내기들. 그건 진정한 해적인 내게 어울리는 물건이다.","JPN":"お宝を渡せ、青二才ども。その代物は、真の海賊である俺にこそふさわしい。","ENG":"Hand me the treasure, lubbers. That's for a real pirate, like me.","TWN":"交出寶藏，菜鳥們。那些東西屬於像我這樣真正的海盜。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DUCK_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_CARTOON"},{"id":"L2_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"과연. 얼추 감이 오는군요.","JPN":"なるほど、そういうことですか。","ENG":"Ahh. Credere understands what's happening.","TWN":"原來如此。克蕾妲莉懂了。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"저 악당스러운 안대. 아무래도 해적단의 상대인 것 같습니다.","JPN":"いかにも悪党らしいその眼帯。クレデレたちの出番ですね。","ENG":"That villainous eyepatch tells Credere that he is our opponent.","TWN":"那副壞蛋般的眼罩，看來是海盜團的對手。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"좋아, 크레데레 선원. 시그마 해적단의 힘으로 바르바로사를 물리치는 거다!","JPN":"よし、クレデレ船員。シグマ海賊団の力でバルバロッサを倒すぞ！","ENG":"Okay, Credere. Let's defeat Barbarossa with the power of the Sigma Pirates!","TWN":"好，克蕾妲莉船員。用西格瑪海盜團的力量擊敗巴巴羅薩吧！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"맡겨만 주시죠. 물먹은 미스터 쮸빕은 물총계의 베스트셀러입니다.","JPN":"お任せください。水を入れたミスター・チュピーは水鉄砲界のベストセラーですから。","ENG":"Leave it to Credere. A wet Mr. Squirty is the bestseller in the water gun category.","TWN":"交給克蕾妲莉吧。濕透的咻咻先生可是水槍界的暢銷品。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"DUCK_DEBT_NULL_NULL","text":{"KOREA":"후후. 바람이 빠진 덕에 물속에서 더욱 빠르게 움직일 수 있지.","JPN":"ふふ、空気が抜けたおかげで、水中での動きがさらに俊敏になったぞ。","ENG":"Ha ha. I can move even faster underwater thanks to the deflation.","TWN":"呵呵。因為漏氣，我在水中能移動得更快。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DUCK_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DUCK_DEBT_NULL_NULL","text":{"KOREA":"이게 바로 진정한 해적의 속도다, 풋내기들!","JPN":"これが真の海賊のスピードだぜ、青二才ども！","ENG":"This is the speed of a true pirate, you lubbers!","TWN":"這才是真正的海盜速度，菜鳥們！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L9_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"어쩔 수 없군요, 시그마. 저희도 비장의 해적 수영법입니다.","JPN":"仕方ありませんね、シグマ。私たちも必殺海賊泳ぎを出しましょう。","ENG":"We have no choice, Sigma. Let us show him the secret pirate swimming technique.","TWN":"沒辦法了，西格瑪。我們也要用上海盜游泳密技了。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응! 나 아까 유피랑 잔뜩 연습했다?","JPN":"うん！　さっきユピともたくさん練習したよ！","ENG":"Okay! I practiced a bunch with Yuppie earlier.","TWN":"嗯！西格瑪和悠菲已經練習了好久呢？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"흡. 하. 흡. 하!","JPN":"すう、はあ！　すう、はあ！","ENG":"Hmph. Hah. Hmph. Hah!","TWN":"呼，哈，呼，哈！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"저기~ 보물상자는 저한테 있는데요~?","JPN":"あの～、宝箱なら私が持ってますけど？","ENG":"Heeeey. I have the treasure chest, though.","TWN":"那個～～寶箱在我這裡喔～～？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"시그마~ 크레데레~ 제 말 들려요~?","JPN":"シグマ～クレデレ～聞こえていますか～？","ENG":"Sigma! Credere! Can you hear me?","TWN":"西格瑪～～克蕾妲莉～～有聽到我說話嗎～～？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"에휴.","JPN":"はあ……","ENG":"*Sigh*","TWN":"……呼。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그러니까 뭐가 해적이라는 건지, 원.","JPN":"これの何が海賊なの、もう。","ENG":"How is this related to being a pirate, anyway?","TWN":"所以，到底和海盜有什麼關係啊……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};